import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
// FontAwesome icons (Make sure to include CDN in index.html)

function Register() {
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    password: '',
    serviceType: 'Web Development',
    paymentMethod: 'Online',
    transactionId: '',
    projectDetails: 'Standard Project Request'
  });

  const [price, setPrice] = useState(0);

  useEffect(() => {
    const prices = {
      'Web Development': 5000,
      'UI/UX Design': 3000,
      'App Development': 8000,
      'Assignment Support': 500,
      'PPT Design': 300,
      'Report Writing': 400
    };
    setPrice(prices[formData.serviceType]);
  }, [formData.serviceType]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (formData.password.length < 8) {
      alert("❌ Password must be at least 8 characters long!");
      return;
    }
    try {
      const res = await axios.post('http://localhost:5000/api/hire', formData);
      if (res.status === 201) {
        alert("✅ Registration Successful! Please login now.");
        setFormData({ fullName: '', email: '', password: '', serviceType: 'Web Development', paymentMethod: 'Online', transactionId: '', projectDetails: 'Standard Project Request' });
      }
    } catch (err) {
      alert("❌ Error: Server not responding.");
    }
  };

  return (
    <div className="registration-wrapper py-5 min-vh-100 d-flex align-items-center">
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-lg-10 col-xl-9">
            <div className="card shadow-lg border-0 rounded-4 overflow-hidden">
              <div className="row g-0">
                
                {/* Left Side: Info Section */}
                <div className="col-md-5 bg-primary text-white p-5 d-flex flex-column justify-content-center">
                  <h2 className="fw-bold mb-4">Start Your <br/>Project With Me</h2>
                  <p className="opacity-75 mb-5">Get high-quality solutions for Web, App, and Academic requirements with real-time tracking.</p>
                  
                  <div className="d-flex align-items-center mb-3">
                    <div className="icon-circle me-3"><i className="fas fa-check text-primary"></i></div>
                    <span>Fast & Reliable Delivery</span>
                  </div>
                  <div className="d-flex align-items-center mb-3">
                    <div className="icon-circle me-3"><i className="fas fa-shield-alt text-primary"></i></div>
                    <span>Secure Payment & Code</span>
                  </div>
                  <div className="d-flex align-items-center">
                    <div className="icon-circle me-3"><i className="fas fa-chart-line text-primary"></i></div>
                    <span>Live Progress Tracking</span>
                  </div>
                </div>

                {/* Right Side: Form Section */}
                <div className="col-md-7 bg-white p-4 p-lg-5">
                  <div className="mb-4">
                    <h3 className="fw-bold text-dark">Service Registration</h3>
                    <p className="text-muted small">Already have an account? <Link to="/login" className="text-primary fw-bold text-decoration-none">Login here</Link></p>
                  </div>

                  <form onSubmit={handleSubmit}>
                    <div className="row g-3">
                      <div className="col-md-6">
                        <label className="form-label small fw-bold">Full Name</label>
                        <input type="text" name="fullName" value={formData.fullName} className="form-control custom-input" placeholder="John Doe" required onChange={handleChange} />
                      </div>
                      <div className="col-md-6">
                        <label className="form-label small fw-bold">Email Address</label>
                        <input type="email" name="email" value={formData.email} className="form-control custom-input" placeholder="john@example.com" required onChange={handleChange} />
                      </div>
                      <div className="col-12">
                        <label className="form-label small fw-bold">Create Password</label>
                        <input type="password" name="password" value={formData.password} className="form-control custom-input" placeholder="Min 8 characters" required onChange={handleChange} />
                      </div>
                      <div className="col-12">
                        <label className="form-label small fw-bold">Choose Service</label>
                        <select name="serviceType" className="form-select custom-input" value={formData.serviceType} onChange={handleChange}>
                          <option value="Web Development">Web Development</option>
                          <option value="UI/UX Design">UI/UX Design</option>
                          <option value="App Development">App Development</option>
                          <option value="Assignment Support">Assignment Support</option>
                          <option value="PPT Design">PPT Design</option>
                          <option value="Report Writing">Report Writing</option>
                        </select>
                      </div>

                      {/* Pricing Display */}
                      <div className="col-12 mt-4">
                        <div className="p-3 bg-light rounded-3 border d-flex justify-content-between align-items-center">
                          <span className="fw-bold text-muted">Estimated Fee:</span>
                          <h4 className="fw-bold text-primary mb-0">₹{price}</h4>
                        </div>
                      </div>

                      <div className="col-12">
                        <button type="submit" className="btn btn-primary w-100 fw-bold py-3 mt-3 shadow-sm rounded-pill">
                          Submit & Create Account
                        </button>
                      </div>
                    </div>
                  </form>
                </div>

              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .registration-wrapper { background-color: #f0f2f5; }
        .custom-input { padding: 12px; border-radius: 8px; border: 1px solid #ddd; font-size: 0.9rem; }
        .custom-input:focus { box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.1); border-color: #0d6efd; }
        .icon-circle { width: 30px; height: 30px; background: white; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 0.8rem; }
        .bg-primary { background: linear-gradient(135deg, #1e3c72 0%, #2a5298 100%) !important; }
      `}</style>
    </div>
  );
}

export default Register;
